class Solution:
    def removeComments(self, source):
        joined = '\n'.join(source)
        out = []
        i = 0
        n = len(joined)
        cur = []
        in_block = False
        while i < n:
            ch = joined[i]
            two = joined[i:i+2]
            if in_block:
                if two == '*/':
                    in_block = False
                    i += 2
                else:
                    i += 1
            else:
                if two == '/*':
                    in_block = True
                    i += 2
                elif two == '//':
                    # skip until newline
                    while i < n and joined[i] != '\n':
                        i += 1
                elif ch == '\n':
                    if cur:
                        out.append(''.join(cur))
                        cur = []
                    i += 1
                else:
                    cur.append(ch)
                    i += 1
        if cur and not in_block:
            out.append(''.join(cur))
        return out

