class Solution:
    def removeComments(self, source):
        out = []
        buf = []
        in_block = False
        for line in source:
            i = 0
            m = len(line)
            while i < m:
                if not in_block:
                    if line[i:i+2] == '//':
                        break
                    elif line[i:i+2] == '/*':
                        in_block = True
                        i += 2
                    else:
                        buf.append(line[i])
                        i += 1
                else:
                    if line[i:i+2] == '*/':
                        in_block = False
                        i += 2
                    else:
                        i += 1
            if not in_block and buf:
                out.append(''.join(buf))
                buf = []
        return out

