var removeComments = function(source) {
    const out = [];
    let buf = [];
    let inBlock = false;
    for (const line of source) {
        let i = 0;
        const m = line.length;
        while (i < m) {
            if (!inBlock) {
                if (line.substr(i, 2) === '//') {
                    break;
                } else if (line.substr(i, 2) === '/*') {
                    inBlock = true;
                    i += 2;
                } else {
                    buf.push(line[i]);
                    i += 1;
                }
            } else {
                if (line.substr(i, 2) === '*/') {
                    inBlock = false;
                    i += 2;
                } else {
                    i += 1;
                }
            }
        }
        if (!inBlock && buf.length) {
            out.push(buf.join(''));
            buf = [];
        }
    }
    return out;
};
